import {
  type AnyShape,
  cell,
  circle,
  Diagram,
  derive,
  EventBus,
  label,
  linear,
  loop,
  type Mount,
  num,
  type Path,
  path,
  play,
  readNow,
  rect,
  tokens,
  type Val,
  Vec,
  vec,
} from "@bireactive";
import * as R from "./rand";

export class MdCircuit extends Diagram {
  protected scene(s: Mount): void {
    this.view(600, 360);
    const anim = this.anim;
    const bus = new EventBus();

    /** Circle + label that scale-pulses on `ev`. */
    const source = (x: number, y: number, lbl: string, ev: string) => {
      const c = circle(vec(x, y), 18);
      s(c, label(c.center, lbl, { bold: true }));
      anim.start(
        loop(function* () {
          yield bus.until(ev);
          yield* c.scale.to({ x: 1.4, y: 1.4 }, 0.08).to({ x: 1, y: 1 }, 0.3);
        }),
      );

