    // a reactive effect (a layout-only change would re-run it and dispose the
    // node shapes' attribute bindings). The toggle highlight stays reactive.
    this.#toggle(
      s,
      14,
      16,
      "graph",
      TOPOS.map(t => t.name),
      topo,
      i => {
        this.#rebuild(TOPOS[i]!);
