// The writable hierarchy used by all demos. Same shape as the bireactive
// spike's treemap — Num.lens at branches gives automatic sum aggregation
// AND a sum-redistribute inverse for writes.
//
// Cells live module-scope so multiple component instances see the same
// writable tree. This is the "shared cells = shared updates" property
// that bireactive uniquely gives us — no event plumbing required.

import { Num, num, type Writable } from "bireactive";

export interface BiNode {
  label: string;
  color: string;
  total: Writable<Num>;
  children?: BiNode[];
}

function leaf(label: string, value: number, color: string): BiNode {
  return { label, color, total: num(value) };
}

function group(label: string, color: string, children: BiNode[]): BiNode {
  const total = Num.lens(
    children.map((c) => c.total),
    (vs: readonly number[]) => vs.reduce((a, b) => a + b, 0),
    (target, vs) => {
      const arr = vs as readonly number[];
      const cur = arr.reduce((a, b) => a + b, 0);
      if (cur === 0) return arr.map(() => target / arr.length) as never;
      const scale = target / cur;
      return arr.map((v) => v * scale) as never;
    },
  );
  return { label, color, total, children };
}

/** Build the shared portfolio tree once. */
export const sharedTree: BiNode = group("Portfolio", "#222", [
  group("Tech", "#5b8def", [
    leaf("AAPL", 35, "#86acf5"),
    leaf("MSFT", 28, "#86acf5"),
    leaf("NVDA", 22, "#86acf5"),
  ]),
  group("Finance", "#7ed321", [
    leaf("JPM", 18, "#a6df5e"),
    leaf("BRK", 14, "#a6df5e"),
  ]),
  group("Energy", "#f5a623", [
    leaf("XOM", 10, "#f7be5a"),
    leaf("SHEL", 8, "#f7be5a"),
  ]),
  group("Health", "#e25c5c", [
    leaf("JNJ", 9, "#ec8a8a"),
    leaf("PFE", 6, "#ec8a8a"),
  ]),
]);

/** All leaves, in source order. Useful for cmd+wheel scrub on focused leaf. */
export function leaves(root: BiNode): BiNode[] {
  const out: BiNode[] = [];
  const walk = (n: BiNode) => {
    if (!n.children) out.push(n);
    else n.children.forEach(walk);
  };
  walk(root);
  return out;
}

export function parentOf(root: BiNode, target: BiNode): BiNode | undefined {
  if (!root.children) return undefined;
  if (root.children.includes(target)) return root;
  for (const c of root.children) {
    const p = parentOf(c, target);
    if (p) return p;
  }
  return undefined;
}
// bireactiveStore — adapt a bireactive Cell to Svelte's store contract.
//
// Why this exists: LayerChart (and any Svelte component) consumes data via
// Svelte stores ({ subscribe, set, update }). Bireactive owns the data model
// (writable Num cells, branch lenses, automatic aggregation). This bridge
// lets a Svelte component read/write bireactive cells transparently.
//
// Implementation: `effect(fn)` re-runs `fn` whenever any cell read in `fn`
// changes. That's exactly Svelte's store-subscribe contract.

import { effect, type Cell, type Writable } from "bireactive";

export interface ReadableStore<T> {
  subscribe: (run: (value: T) => void) => () => void;
}

export interface WritableStore<T> extends ReadableStore<T> {
  set: (value: T) => void;
  update: (updater: (value: T) => T) => void;
}

/**
 * Wrap a read-only bireactive cell as a Svelte readable store.
 * `read` is called every time the store should fire (typically `() => cell.value`).
 */
export function readableFromCell<T>(read: () => T): ReadableStore<T> {
  return {
    subscribe(run) {
      // effect() runs the inner fn once immediately, then re-runs on cell change.
      const dispose = effect(() => {
        const v = read();
        run(v);
      });
      return dispose;
    },
  };
}

/**
 * Wrap a writable bireactive cell (Writable<Num>, or any Cell with .value setter)
 * as a Svelte writable store. Writes go straight back into the cell — the cell's
 * lens (if any) handles the inverse propagation.
 */
export function writableFromCell<T extends { value: any }>(
  cell: Writable<T>,
): WritableStore<T["value"]> {
  return {
    subscribe(run) {
      const dispose = effect(() => {
        run(cell.value);
      });
      return dispose;
    },
    set(v) {
      cell.value = v;
    },
    update(fn) {
      cell.value = fn(cell.value);
    },
  };
}

/**
 * Most general: derive a Svelte store from an arbitrary reactive read.
 * Useful for projections (e.g. mapping a Vec cell to {x, y}).
 */
export function derivedStore<T>(read: () => T): ReadableStore<T> {
  return readableFromCell(read);
}

/**
 * Plain Cell<T> as a readable store. Cell has `.value`; effect tracks reads.
 */
export function cellStore<T>(cell: Cell<T>): ReadableStore<T> {
  return readableFromCell(() => cell.value);
}
// Shared direct-manipulation logic for the LayerChart hierarchy demos
// (treemap, sunburst, icicle, pack). Each viz differs in geometry but the
// gesture model and write semantics are identical: hover-targeted scrub with
// a sticky modifier-held lock, Tab navigation, arrow nudges, and writes that
// flow through the Num.lens at each branch.

import { hierarchy } from "d3-hierarchy";
import { effect as biEffect } from "bireactive";
import { sharedTree, leaves, parentOf, type BiNode } from "./tree";

/**
 * Redistribute a value change across the tree so the parent total is preserved.
 * Writes to a branch node go through its Num.lens (children rescale
 * proportionally); siblings of the target absorb the delta either by
 * proportional shrink (growing the target) or proportional grow (shrinking it).
 */
export function applyDelta(node: BiNode, delta: number) {
  const parent = parentOf(sharedTree, node);
  if (!parent || !parent.children) return;
  const siblings = parent.children.filter((c) => c !== node);
  const cur = node.total.value;
  const next = Math.max(0, cur + delta);
  const real = next - cur;
  if (real === 0) return;
  node.total.value = next;
  let remaining = real;
  if (real > 0) {
    const pool = siblings.filter((s) => s.total.value > 0);
    const poolSum = pool.reduce((a, b) => a + b.total.value, 0);
    if (poolSum > 0) {
      for (const sib of pool) {
        const share = (sib.total.value / poolSum) * real;
        const take = Math.min(sib.total.value, share);
        sib.total.value -= take;
        remaining -= take;
      }
      for (const sib of siblings) {
        if (remaining <= 0) break;
        const take = Math.min(sib.total.value, remaining);
        sib.total.value -= take;
        remaining -= take;
      }
    }
  } else if (siblings.length > 0) {
    const sibSum = siblings.reduce((a, b) => a + b.total.value, 0);
    if (sibSum > 0) {
      for (const sib of siblings) {
        const share = (sib.total.value / sibSum) * -real;
        sib.total.value += share;
      }
    } else {
      for (const sib of siblings) sib.total.value += -real / siblings.length;
    }
  }
}

/** Depth-first node order, excluding the root. Used for Tab navigation. */
export function flatOrder(root: BiNode): BiNode[] {
  const out: BiNode[] = [];
  const walk = (n: BiNode) => {
    if (n !== root) out.push(n);
    n.children?.forEach(walk);
  };
  walk(root);
  return out;
}

/**
 * Build a d3 hierarchy snapshot of the shared bireactive tree. Caller passes
 * the version signal so this re-runs whenever any leaf cell changes.
 */
export function buildHierarchy() {
  return hierarchy<BiNode>(sharedTree, (n) => n.children)
    .sum((n) => (n.children ? 0 : n.total.value));
}

/**
 * Subscribe to every leaf's total. Returns the dispose function. Use inside
 * onDestroy. The caller passes a callback that should bump a Svelte $state
 * value, which downstream $derived.by reads to re-run.
 */
export function subscribeAllLeaves(onChange: () => void) {
  const allLeaves = leaves(sharedTree);
  return biEffect(() => {
    for (const l of allLeaves) void l.total.value;
    onChange();
  });
}

/**
 * Install a window-level keyup/blur listener that fires `release()` when
 * cmd/ctrl is released or the window loses focus. Used to clear the wheel
 * gesture lock. Element-level listeners miss this because wheels don't
 * transfer focus and inside a customElement shadow root focus often stays
 * on document.body.
 *
 * Call from inside `$effect(() => installGestureRelease(release))` so it
 * tears down with the component.
 */
export function installGestureRelease(release: () => void): () => void {
  const onKeyup = (e: KeyboardEvent) => {
    if (e.key === "Meta" || e.key === "Control" || (!e.metaKey && !e.ctrlKey)) {
      release();
    }
  };
  const onBlur = () => release();
  window.addEventListener("keyup", onKeyup);
  window.addEventListener("blur", onBlur);
  return () => {
    window.removeEventListener("keyup", onKeyup);
    window.removeEventListener("blur", onBlur);
  };
}

