116	  readonly #src: Writable<Cell<readonly E[]>>;
117	
118	  constructor(items: readonly E[], key: (e: E) => unknown) {
119	    const src = cell<readonly E[]>(items);
120	    super(src, key, null);
121	    this.#src = src;
122	  }
123	
124	  override assertContains(e: E): void {
125	    if (!this.#src.value.includes(e)) this.insert(e);
126	  }
127	
128	  insert(e: E, at?: number): void {
129	    const arr = [...this.#src.value];
130	    if (at == null) arr.push(e);
131	    else arr.splice(at, 0, e);
132	    this.#src.value = arr;
133	  }
134	
135	  removeFromSource(e: E): void {
136	    this.#src.value = this.#src.value.filter(x => x !== e);
137	  }
138	}
